import React, { useState, useRef, useEffect } from 'react';
import { QrCode, UserPlus, Clock, CheckCircle, LogOut, KeyRound, X } from 'lucide-react';
import { Html5Qrcode } from 'html5-qrcode';
import { Button } from './ui/button';
import { Card } from './ui/card';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from './ui/dialog';
import { SenaLogo } from './SenaLogo';

interface User {
  id: string;
  name: string;
  document: string;
  role: string;
  status: string;
  lastAccess?: string;
}

interface GuardScreenProps {
  onRegisterNew: () => void;
  onLogout: () => void;
}

export function GuardScreen({ onRegisterNew, onLogout }: GuardScreenProps) {
  const [scannedUser, setScannedUser] = useState<User | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [showManualEntry, setShowManualEntry] = useState(false);
  const [manualDocument, setManualDocument] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const qrCodeRef = useRef<Html5Qrcode | null>(null);
  const scannerContainerRef = useRef<HTMLDivElement | null>(null);

  // Manejar resultado del escaneo QR
  const handleScanResult = async (data: string) => {
    if (!data) return;

    console.log('QR detectado:', data);

    // Detener el escáner
    if (qrCodeRef.current) {
      try {
        await qrCodeRef.current.stop();
        qrCodeRef.current.clear();
      } catch (error) {
        console.error('Error al detener escáner:', error);
      }
    }

    setIsScanning(false);

    try {
      // Obtener token de autenticación del localStorage o contexto
      const token = localStorage.getItem('token');

      // Enviar al backend para procesar el registro
      const response = await fetch('http://localhost:3000/api/registro/scan', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          qr: data,
          tipo: 'entrada', // Por defecto entrada, se puede cambiar según lógica
        }),
      });

      const result = await response.json();

      if (result.registered && result.user) {
        // Mapear respuesta del backend al formato del componente
        const user: User = {
          id: result.user.id_usuario.toString(),
          name: result.user.nombre,
          document: result.user.identificacion,
          role: 'Usuario', // Se puede obtener del rol si está disponible
          status: 'Activo',
          lastAccess: result.attendance?.hora_entrada || new Date().toLocaleTimeString(),
        };
        setScannedUser(user);
      } else {
        alert(result.message || 'Usuario no registrado');
      }
    } catch (error) {
      console.error('Error al procesar QR:', error);
      alert('Error al procesar el código QR. Por favor, intente nuevamente.');
    }
  };

  // Iniciar escáner QR
  const startQRScanner = async () => {
    if (!scannerContainerRef.current) return;

    setIsScanning(true);

    try {
      // Esperar un momento para que el DOM se actualice
      await new Promise(resolve => setTimeout(resolve, 100));

      const html5QrCode = new Html5Qrcode('qr-reader');
      qrCodeRef.current = html5QrCode;

      await html5QrCode.start(
        { facingMode: 'environment' },
        {
          fps: 10,
          qrbox: { width: 250, height: 250 },
        },
        (decodedText) => {
          handleScanResult(decodedText);
        },
        (errorMessage) => {
          // Silenciar errores de escaneo continuo
        }
      );
    } catch (error) {
      console.error('Error al iniciar cámara:', error);
      alert('Error al acceder a la cámara. Por favor, verifique los permisos.');
      setIsScanning(false);
    }
  };

  // Detener escáner QR
  const stopQRScanner = async () => {
    if (qrCodeRef.current) {
      try {
        await qrCodeRef.current.stop();
        qrCodeRef.current.clear();
        qrCodeRef.current = null;
      } catch (error) {
        console.error('Error al detener escáner:', error);
      }
    }
    setIsScanning(false);
  };

  // Limpiar escáner al desmontar componente
  useEffect(() => {
    return () => {
      if (qrCodeRef.current) {
        qrCodeRef.current.stop().catch(() => {});
        qrCodeRef.current.clear();
      }
    };
  }, []);

  // Búsqueda manual por cédula
  const handleManualSearch = async (e: any) => {
    e.preventDefault();

    if (!manualDocument.trim()) {
      alert('Por favor ingrese un número de cédula');
      return;
    }

    setIsSearching(true);

    try {
      const token = localStorage.getItem('token');

      const response = await fetch('http://localhost:3000/api/registro/manual', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          identificacion: manualDocument,
          tipo: 'entrada',
        }),
      });

      const result = await response.json();

      if (result.registered && result.user) {
        const user: User = {
          id: result.user.id_usuario.toString(),
          name: result.user.nombre,
          document: result.user.identificacion,
          role: 'Usuario',
          status: 'Activo',
          lastAccess: result.attendance?.hora_entrada || new Date().toLocaleTimeString(),
        };
        setScannedUser(user);
        setShowManualEntry(false);
        setManualDocument('');
      } else {
        alert(result.message || 'Usuario no encontrado');
      }
    } catch (error) {
      console.error('Error al buscar usuario:', error);
      alert('Error al buscar usuario. Por favor, intente nuevamente.');
    } finally {
      setIsSearching(false);
    }
  };

  const registerEntry = async () => {
    if (!scannedUser) return;

    try {
      const token = localStorage.getItem('token');

      const response = await fetch('http://localhost:3000/api/registro/scan', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          qr: scannedUser.document,
          tipo: 'entrada',
        }),
      });

      const result = await response.json();

      if (result.registered) {
        alert(`Entrada registrada para ${scannedUser.name} a las ${result.attendance?.hora_entrada || new Date().toLocaleTimeString()}`);
        setScannedUser(null);
      } else {
        alert(result.message || 'Error al registrar entrada');
      }
    } catch (error) {
      console.error('Error al registrar entrada:', error);
      alert('Error al registrar entrada. Por favor, intente nuevamente.');
    }
  };

  const registerExit = async () => {
    if (!scannedUser) return;

    try {
      const token = localStorage.getItem('token');

      const response = await fetch('http://localhost:3000/api/registro/scan', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          qr: scannedUser.document,
          tipo: 'salida',
        }),
      });

      const result = await response.json();

      if (result.registered) {
        alert(`Salida registrada para ${scannedUser.name} a las ${result.attendance?.hora_salida || new Date().toLocaleTimeString()}`);
        setScannedUser(null);
      } else {
        alert(result.message || 'Error al registrar salida');
      }
    } catch (error) {
      console.error('Error al registrar salida:', error);
      alert('Error al registrar salida. Por favor, intente nuevamente.');
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-emerald-50 via-green-50 to-teal-50 p-4">
      {/* Header */}
      <div className="max-w-md mx-auto mb-8 pt-4">
        <div className="flex items-center justify-between mb-6">
          <div className="inline-flex items-center gap-3 bg-white/80 backdrop-blur-sm px-4 py-3 rounded-2xl shadow-md">
            <SenaLogo size="md" />
            <div className="text-left">
              <h1 className="text-lg font-semibold text-[var(--sena-blue)]">CBI SENA Palmira</h1>
              <p className="text-sm text-gray-600">Control de Acceso</p>
            </div>
          </div>
          <Button 
            onClick={onLogout}
            variant="outline"
            size="sm"
            className="text-[var(--sena-blue)] border-2 border-[var(--sena-blue)] hover:bg-emerald-50 rounded-xl transition-all duration-300 shadow-md"
          >
            <LogOut className="w-4 h-4 mr-1" />
            Cerrar Sesión
          </Button>
        </div>
      </div>

      <div className="max-w-md mx-auto space-y-6">
        {/* Scanner Section */}
        <Card className="p-10 text-center shadow-xl rounded-2xl border-0 bg-white/80 backdrop-blur-sm">
          {!isScanning ? (
            <>
              <div className="mb-8">
                <div className="w-40 h-40 mx-auto rounded-3xl border-4 border-dashed border-gray-300 bg-gradient-to-br from-gray-50 to-gray-100 flex items-center justify-center transition-all duration-500">
                  <QrCode className="w-20 h-20 text-gray-400" />
                </div>
              </div>

              <Button 
                onClick={startQRScanner}
                className="w-full h-16 bg-gradient-to-r from-[var(--sena-blue)] to-[#0077A3] hover:from-[#0077A3] hover:to-[#005580] shadow-lg hover:shadow-xl transition-all duration-300 rounded-xl mb-3"
              >
                <QrCode className="w-5 h-5 mr-2" />
                Escanear Código QR
              </Button>

              <Button 
                onClick={() => setShowManualEntry(true)}
                variant="outline"
                className="w-full h-14 border-2 border-[var(--sena-blue)] text-[var(--sena-blue)] hover:bg-[var(--sena-gray-light)] shadow-md hover:shadow-lg transition-all duration-300 rounded-xl"
              >
                <KeyRound className="w-5 h-5 mr-2" />
                Ingreso manual (por cédula)
              </Button>
            </>
          ) : (
            <div className="scanner-box">
              <div className="mb-4">
                <div className="w-full max-w-sm mx-auto rounded-2xl overflow-hidden shadow-lg border-4 border-[var(--sena-green)] bg-black">
                  <div
                    id="qr-reader"
                    ref={scannerContainerRef}
                    className="w-full"
                    style={{ minHeight: '300px' }}
                  />
                </div>
              </div>

              <Button
                onClick={stopQRScanner}
                variant="outline"
                className="w-full h-14 border-2 border-red-500 text-red-500 hover:bg-red-50 shadow-md hover:shadow-lg transition-all duration-300 rounded-xl"
              >
                <X className="w-5 h-5 mr-2" />
                Cerrar cámara
              </Button>
            </div>
          )}
        </Card>

        {/* User Info */}
        {scannedUser && (
          <Card className="p-7 border-2 border-[var(--sena-green)] shadow-xl rounded-2xl bg-gradient-to-br from-green-50 to-emerald-50 animate-in fade-in duration-500">
            <div className="flex items-center gap-4 mb-6">
              <div className="w-14 h-14 bg-gradient-to-br from-[var(--sena-green)] to-green-600 rounded-2xl flex items-center justify-center shadow-lg">
                <CheckCircle className="w-7 h-7 text-white" />
              </div>
              <div>
                <h3 className="font-semibold text-[var(--sena-blue)] text-lg">{scannedUser.name}</h3>
                <p className="text-sm text-gray-600 mt-1">{scannedUser.role} • {scannedUser.status}</p>
                <p className="text-xs text-gray-500 mt-1">Doc: {scannedUser.document}</p>
              </div>
            </div>

            {scannedUser.lastAccess && (
              <div className="flex items-center gap-2 mb-6 p-3 bg-white/50 rounded-xl">
                <Clock className="w-4 h-4 text-[var(--sena-green)]" />
                <span className="text-sm text-gray-700">Último acceso: {scannedUser.lastAccess}</span>
              </div>
            )}

            <div className="grid grid-cols-2 gap-3">
              <Button 
                onClick={registerEntry}
                className="h-14 bg-gradient-to-r from-[var(--sena-green)] to-green-600 hover:from-green-600 hover:to-green-700 shadow-md hover:shadow-lg transition-all duration-300 rounded-xl"
              >
                Registrar Entrada
              </Button>
              <Button 
                onClick={registerExit}
                variant="outline"
                className="h-14 border-2 border-[var(--sena-green)] text-[var(--sena-green)] hover:bg-green-50 shadow-md hover:shadow-lg transition-all duration-300 rounded-xl"
              >
                Registrar Salida
              </Button>
            </div>
          </Card>
        )}

        {/* Register New Person */}
        <Card className="p-5 shadow-lg rounded-2xl border-0 bg-white/80 backdrop-blur-sm hover:shadow-xl transition-all duration-300">
          <Button 
            onClick={onRegisterNew}
            variant="outline"
            className="w-full h-14 border-dashed border-2 border-gray-300 hover:border-[var(--sena-blue)] hover:bg-gradient-to-r hover:from-emerald-50 hover:to-green-50 transition-all duration-300 rounded-xl"
          >
            <UserPlus className="w-5 h-5 mr-2" />
            Registrar Nueva Persona
          </Button>
        </Card>
      </div>

      {/* Manual Entry Modal */}
      <Dialog open={showManualEntry} onOpenChange={setShowManualEntry}>
        <DialogContent className="max-w-md rounded-2xl border-0 shadow-2xl">
          <DialogHeader>
            <DialogTitle className="text-2xl text-[var(--sena-blue)] flex items-center gap-2">
              <KeyRound className="w-6 h-6" />
              Ingreso Manual
            </DialogTitle>
            <DialogDescription className="text-gray-600">
              Ingrese el número de cédula de la persona
            </DialogDescription>
          </DialogHeader>

          <form onSubmit={handleManualSearch} className="space-y-6 mt-4">
            <div className="space-y-2">
              <Label htmlFor="document" className="text-gray-700">Número de Cédula *</Label>
              <Input
                id="document"
                value={manualDocument}
                onChange={(e) => setManualDocument(e.target.value)}
                placeholder="Ej: 1234567890"
                className="h-14 rounded-xl border-gray-200 focus:border-[var(--sena-green)] focus:ring-[var(--sena-green)] transition-all duration-300 text-lg"
                required
                autoFocus
              />
            </div>

            <div className="flex gap-3">
              <Button
                type="button"
                variant="outline"
                className="flex-1 h-12 rounded-xl border-2 hover:bg-gray-50 transition-all duration-300"
                onClick={() => {
                  setShowManualEntry(false);
                  setManualDocument('');
                }}
              >
                Cancelar
              </Button>
              <Button
                type="submit"
                disabled={isSearching}
                className="flex-1 h-12 bg-gradient-to-r from-[var(--sena-green)] to-green-600 hover:from-green-600 hover:to-green-700 shadow-lg hover:shadow-xl transition-all duration-300 rounded-xl disabled:opacity-50"
              >
                {isSearching ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2" />
                    Buscando...
                  </>
                ) : (
                  'Buscar'
                )}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}
